def test_restricted_knowledge_reply_requires_project_admin_for_mutation() -> None:
    reply = {"id": "reply-1", "knowledgeOutputRestricted": True}

    with pytest.raises(admin_issue_api.HTTPException) as exc_info:
        admin_issue_api._require_reply_knowledge_access(reply, actor_role="editor")

    assert exc_info.value.status_code == 403
    admin_issue_api._require_reply_knowledge_access(reply, actor_role="admin")


@pytest.fixture(autouse=True)
def _default_email_webhook_token(monkeypatch):
    monkeypatch.setenv("SUPPORT_EMAIL_WEBHOOK_TOKEN", "email-token")
    monkeypatch.setenv("SMTP_HOST", "smtp.example.test")
    monkeypatch.setenv("SMTP_FROM", "support@example.test")

    def fake_claim_issue_reply_delivery(*, reply, **_kwargs):
        attempt_key = f"support-outbound:{reply['id']}"
        metadata = {
            **issues._parse(reply.get("metadata"), dict),
            "deliveryAttemptKey": attempt_key,
            "deliveryCertainty": "in_flight",
        }
        return {
            "claimed": True,
            "state": "sending",
            "claim_token": "test-delivery-claim",
            "attempt_key": attempt_key,
            "claimed_at": issues._now_iso(),
            "outbound": {**reply, "status": "sending", "metadata": metadata},
        }

    def fake_complete_issue_reply_delivery(**kwargs):
        reply = kwargs["reply"]
        status = kwargs["status"]
        metadata = {
            **kwargs["metadata_after"],
            "deliveryCertainty": kwargs["certainty"],
        }
        data = {
            "status": status,
            "provider": kwargs["provider"],
            "provider_message_id": kwargs["provider_message_id"],
            "error": kwargs["error"],
            "metadata": metadata,
        }
        if status == "sent":
            data["sent_at"] = kwargs["sent_at"]
        issues._patch(
            f"/api/collections/support_outbound_messages/records/{reply['id']}",
            data,
        )
        return {**reply, **data}

    monkeypatch.setattr(issues, "_claim_issue_reply_delivery", fake_claim_issue_reply_delivery)
    monkeypatch.setattr(issues, "_complete_issue_reply_delivery", fake_complete_issue_reply_delivery)
    monkeypatch.setattr(
        issues,
        "_apply_direct_channel_runbooks",
        lambda *, issue, **_kwargs: issue,
    )


def test_send_support_email_reply_attaches_files(monkeypatch):
    sent_messages: list[object] = []

    class FakeSMTP:
        def __init__(self, host: str, port: int, timeout: int | None = None):
            self.host = host
            self.port = port
            self.timeout = timeout

        def __enter__(self):
            return self

        def __exit__(self, *_args):
            return False

        def ehlo(self):
            return None

        def starttls(self):
            return None

        def login(self, *_args):
            return None

        def send_message(self, message):
            sent_messages.append(message)

    monkeypatch.setenv("SMTP_HOST", "smtp.example.com")
    monkeypatch.setenv("SMTP_FROM", "support@example.com")
    monkeypatch.setattr(support_delivery.smtplib, "SMTP", FakeSMTP)

    result = support_delivery.send_support_email_reply(
        message_id="reply123",
        to_address="customer@example.com",
        from_address="agent@example.com",
        subject="Re: Need help",
        body="See attached.",
        attachments=[{"filename": "quote.pdf", "base64": "cGRm", "contentType": "application/pdf"}],
    )

    assert result.status == "sent"
    assert len(sent_messages) == 1
    assert sent_messages[0]["Message-ID"] == (
        "<c85251546fc1237a48b4acbe9f9b5e3f09e6ea09dfdf9bbb5f82265f2678ad44@mantly.delivery>"
    )
    attachments = list(sent_messages[0].iter_attachments())
    assert attachments[0].get_filename() == "quote.pdf"
    assert attachments[0].get_content_type() == "application/pdf"
    assert attachments[0].get_payload(decode=True) == b"pdf"


