def test_send_support_email_reply_prefers_channel_webhook(monkeypatch):
    calls: list[dict] = []

    def fake_send_support_channel_reply(**kwargs):
        calls.append(kwargs)
        return DeliveryResult(
            status="sent",
            provider="email_webhook",
            provider_message_id="email:reply123",
            metadata={"deliveryRoute": {"channel": "email", "transport": "webhook"}},
        )

    monkeypatch.setattr(support_delivery, "send_support_channel_reply", fake_send_support_channel_reply)

    result = support_delivery.send_support_email_reply(
        message_id="reply123",
        to_address="customer@example.com",
        from_address="agent@example.com",
        subject="Re: Need help",
        body="We are checking this.",
        attachments=[{"filename": "quote.pdf", "base64": "cGRm"}],
        channel_config={"outboundWebhookUrl": "https://adapter.example/email"},
        metadata={"issueSource": "channel:email:support"},
        secrets={},
    )

    assert result.status == "sent"
    assert result.provider == "email_webhook"
    assert calls[0]["channel"] == "email"
    assert calls[0]["channel_config"]["outboundWebhookUrl"] == "https://adapter.example/email"
    assert calls[0]["metadata"]["issueSource"] == "channel:email:support"
    assert calls[0]["metadata"]["attachments"][0]["filename"] == "quote.pdf"


