def test_channel_inbound_smoke_proof_records_provider_recipient_targets():
    cases = [
        ("telegram", {"smokeToAddress": "777000"}, "channel_id", "777000", {"chatId": "777000"}),
        ("whatsapp", {"smokeToAddress": "491701234567"}, "thread_id", "491701234567", {"waId": "491701234567", "senderId": "491701234567"}),
        ("messenger", {"smokeToAddress": "psid-live-1"}, "thread_id", "psid-live-1", {"psid": "psid-live-1", "senderId": "psid-live-1"}),
        ("sms", {"smokeToAddress": "+14155550123"}, "thread_id", "+14155550123", {"phone": "+14155550123", "senderId": "+14155550123"}),
    ]

    for channel_type, config, field, expected_value, expected_proof in cases:
        body = admin_channel_api._test_message_with_channel_defaults(
            admin_channel_api.ChannelTestMessageInput(),
            channel_type=channel_type,
            config=config,
        )
        proof = admin_channel_api._inbound_smoke_target_proof(channel_type, body)

        assert getattr(body, field) == expected_value
        for key, value in expected_proof.items():
            assert proof[key] == value


def _slack_attachment_lifecycle_run(
    *,
    provider_delivery: bool = False,
    auth: dict | None = None,
    channel_id: str = "C_LIVE",
    provider: str = "slack",
) -> dict:
    inbound = {"transport": "http", "issueId": "issue-attachment"}
    if auth:
        inbound["http"] = {"auth": auth}
    result = {
        "ready": True,
        "sent": True,
        "inbound": inbound,
        "issueId": "issue-attachment",
        "replyId": "reply-attachment",
        "attachmentCount": 1,
        "fileOnly": True,
    }
    if provider_delivery:
        result.update({
            "providerMessageId": f"{provider}:{channel_id}:file",
            **_provider_delivery_proof(provider=provider, channel_id=channel_id),
        })
    return {
        "id": "lifeSmokeFileOnly1",
        "channel": "channel1",
        "source": "admin-lifecycle-smoke",
        "status": "sent",
        "processed": 1,
        "failed": 0,
        "result": result,
    }


