def _ready_support_schema_health() -> dict:
    return {
        "status": "ready",
        "ready": True,
        "missingCollections": [],
        "missingFields": [],
        "missingMigrationFiles": [],
    }


def test_support_schema_health_reports_missing_collections(monkeypatch):
    missing_names = {"support_messages", "knowledge_articles"}
    seen: list[str] = []
    field_map = {
        name: set(config["fields"])
        for name, config in issues.SUPPORT_SCHEMA_REQUIRED_FIELDS.items()
    }
    field_map["support_issues"].remove("tags")

    def fake_get(path: str) -> dict:
        name = path.rsplit("/", 1)[-1]
        seen.append(name)
        if name in missing_names:
            raise RuntimeError("collection not found")
        return {
            "id": name,
            "fields": [{"name": field_name} for field_name in sorted(field_map.get(name, set()))],
        }

    monkeypatch.setattr(issues, "_get", fake_get)

    result = issues.support_schema_health()

    assert result["status"] == "missing"
    assert result["ready"] is False
    assert result["requiredCollections"] == len(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS)
    assert result["presentCollections"] == len(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS) - len(missing_names)
    assert result["missingCollections"] == ["support_messages", "knowledge_articles"]
    assert result["requiredFields"] == sum(len(config["fields"]) for config in issues.SUPPORT_SCHEMA_REQUIRED_FIELDS.values())
    assert result["presentFields"] == result["requiredFields"] - 1
    assert result["missingFields"] == ["support_issues.tags"]
    assert result["missingMigrationFiles"] == []
    assert {item["name"] for item in result["items"]} == set(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS)
    assert {item["migration"] for item in result["items"] if item["name"] == "support_issues"} == {"25_support_issues.js"}
    assert seen == [*list(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS), "chats"]


def test_support_analytics_returns_schema_blockers_when_collections_missing(monkeypatch):
    def fake_health() -> dict:
        return {
            "status": "missing",
            "ready": False,
            "requiredCollections": len(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS),
            "presentCollections": len(issues.SUPPORT_SCHEMA_REQUIRED_COLLECTIONS) - 1,
            "missingCollections": ["support_messages"],
            "requiredFields": 2,
            "presentFields": 1,
            "missingFields": ["support_issues.tags"],
            "expectedMigrations": 3,
            "presentMigrations": 2,
            "missingMigrationFiles": ["48_support_issue_tags.js"],
            "items": [],
            "fieldItems": [],
            "migrationItems": [],
        }

    def fail_list_all(*_args, **_kwargs):
        raise AssertionError("analytics should not query support collections when schema is missing")

    monkeypatch.setattr(issues, "support_schema_health", fake_health)
    monkeypatch.setattr(issues, "_list_all", fail_list_all)

    summary = issues.support_analytics(tenant_id="tenant1", project_id="project1")

    assert summary["totalIssues"] == 0
    assert summary["activeEmailChannelsWithSync"] == 0
    assert summary["activeEmailChannelsMissingSync"] == 0
    assert summary["failedEmailChannelSyncRuns"] == 0
    assert summary["activeEmailChannelsWithDelivery"] == 0
    assert summary["activeEmailChannelsMissingDelivery"] == 0
    assert summary["activeChannelsWithAttachmentLifecycleSmoke"] == 0
    assert summary["activeChannelsMissingAttachmentLifecycleSmoke"] == 0
    assert summary["channelBacklogSurfaces"] == 0
    assert summary["channelBacklogTypes"] == []
    assert summary["activeSlackChannelsWithAttachmentLifecycleSmoke"] == 0
    assert summary["activeSlackChannelsMissingAttachmentLifecycleSmoke"] == 0
    assert summary["failedAttachmentLifecycleChannelSmokeRuns"] == 0
    assert summary["activeWebChatChannelsWithSession"] == 0
    assert summary["activeWebChatChannelsMissingSession"] == 0
    assert summary["failedWebChatChannelSessionProofs"] == 0
    assert summary["activeWebChatChannelsWithDelivery"] == 0
    assert summary["activeWebChatChannelsMissingDelivery"] == 0
    assert summary["failedWebChatChannelDeliveryProofs"] == 0
    assert summary["launchReadiness"]["status"] == "blocked"
    assert summary["launchReadiness"]["checks"] == 3
    assert summary["launchProof"]["schema"]["ready"] is False
    assert summary["launchProof"]["schema"]["missingCollections"] == ["support_messages"]
    assert summary["launchProof"]["schema"]["missingFields"] == ["support_issues.tags"]
    assert summary["launchProof"]["schema"]["missingMigrationFiles"] == ["48_support_issue_tags.js"]
    assert summary["launchProof"]["channels"] == {
        "total": 0,
        "active": 0,
        "required": 0,
        "ready": 0,
        "blocked": 0,
        "items": [],
    }
    assert summary["launchProof"]["channelBacklog"] == {
        "total": 0,
        "types": [],
        "items": [],
    }
    assert {item["key"] for item in summary["launchReadiness"]["blockers"]} == {
        "schema_collections_missing",
        "schema_fields_missing",
        "schema_migrations_missing",
    }


