    assert lanes["ongoing"]["attention"]["failedDelivery"] == 1
    assert lanes["ongoing"]["attention"]["overdueSla"] == 1
    assert lanes["ongoing"]["operatingAction"]["kind"] == "recover_delivery"
    assert lanes["ongoing"]["operatingAction"]["statusFilter"] == "failed-delivery"
