    assert lanes["done"]["issues"][0]["id"] == "issue-done"
    assert lanes["done"]["policy"]["doneGate"] is True
    assert lanes["done"]["policy"]["entryRequirements"] == [
        "Ticket has an assignee.",
        "No pending approvals, action approvals, queued replies, or failed deliveries.",
    ]
    assert lanes["done"]["operatingAction"]["kind"] == "audit_done"
    assert lanes["done"]["operatingAction"]["blocked"] is False


