def test_issue_answer_workspace_summarizes_ticket_context(monkeypatch):
    def fake_get_issue(issue_id: str, *, tenant_id: str | None, project_id: str) -> dict:
        assert issue_id == "issue1"
        assert tenant_id == "tenant1"
        assert project_id == "project1"
        return {
            "id": "issue1",
            "status": "ongoing",
            "workflowStatus": "ongoing",
            "assigneeEmail": "agent@example.com",
            "contactEmail": "customer@example.com",
            "channel": "slack",
            "source": "channel:slack:support",
            "metadata": {"channelId": "C123", "threadTs": "1719859200.000000"},
            "needsResponse": True,
            "pendingApprovalCount": 1,
            "pendingReplyApprovalCount": 1,
            "pendingActionApprovalCount": 0,
            "outboundMessages": [
                {"id": "reply1", "status": "draft"},
                {"id": "reply2", "status": "sent"},
            ],
            "actionExecutions": [{"id": "action1", "status": "success"}],
            "knowledgeSuggestions": [{"id": "article1"}, {"id": "article2"}],
            "knowledgeGaps": [{"id": "gap1", "status": "open"}, {"id": "gap2", "status": "resolved"}],
            "aiRuns": [
                {
                    "id": "run1",
                    "source": "agent_answer",
                    "summary": "Use the workspace answer.",
                    "metadata": {
                        "question": "What should we answer?",
                        "answer": "Use the workspace answer.",
                        "confidence": "high",
                        "replyId": "reply1",
                        "citations": [{"id": "article1"}],
                    },
                },
                {"id": "run2", "source": "triage", "metadata": {}},
            ],
        }

    monkeypatch.setattr(issues, "get_issue", fake_get_issue)
    monkeypatch.setattr(
        issues,
        "get_channel_by_key",
        lambda channel_key, **_kwargs: {
            "id": "channel1",
            "channelKey": channel_key,
            "type": "slack",
            "status": "active",
            "config": {"outboundTransport": "provider_api"},
        },
    )
    monkeypatch.setattr(issues, "load_runtime_secrets", lambda *_args, **_kwargs: {"SUPPORT_SLACK_BOT_TOKEN": "xoxb-token"})

    workspace = issues.issue_answer_workspace(
        "issue1",
        tenant_id="tenant1",
        project_id="project1",
    )

    assert workspace is not None
    assert workspace["kind"] == "support_issue_answer_workspace"
    assert workspace["nextAction"]["kind"] == "reply_approval"
    assert workspace["nextAction"]["phase"] == "human_review"
    assert workspace["agent"] == {
        "runCount": 1,
        "messageCount": 0,
        "latestMessageId": "",
        "latestAssistantMessageId": "",
        "latestMessagePreview": "",
        "latestRunId": "run1",
        "latestQuestion": "What should we answer?",
        "latestAnswerPreview": "Use the workspace answer.",
        "confidence": "high",
        "citationCount": 1,
        "hasDraft": True,
    }
    assert workspace["knowledge"]["suggestionCount"] == 2
    assert workspace["knowledge"]["openGapCount"] == 1
    assert workspace["knowledge"]["topSuggestionIds"] == ["article1", "article2"]
    assert workspace["reply"]["draftCount"] == 1
    assert workspace["reply"]["sentCount"] == 1
    assert workspace["humanLoop"]["pendingApprovalCount"] == 1
    assert workspace["channel"] == {
        "channel": "slack",
        "source": "channel:slack:support",
        "canAnswerFromApp": True,
    }
    assert workspace["replyReadiness"]["status"] == "ready"
    assert workspace["replyReadiness"]["transport"] == "provider_api"
    assert workspace["replyReadiness"]["provider"] == "slack"
    assert workspace["replyReadiness"]["channelKey"] == "slack:support"
    assert workspace["replyReadiness"]["target"]["value"] == "C123"
    assert workspace["replyReadiness"]["adapter"] == {
        "channel": "slack",
        "selectedTransport": "provider_api",
        "selectedProvider": "slack",
        "supportedTransports": ["provider_api"],
        "nativeProvider": True,
        "webhookAdapter": False,
        "internal": False,
        "requiresChannelConfig": True,
        "channelConfigured": True,
        "requiresRuntimeSecrets": True,
        "requiredEnvVars": ["SUPPORT_SLACK_BOT_TOKEN"],
        "missingEnvVars": [],
        "targetKey": "channelId",
        "targetLabel": "Channel: C123",
    }
    assert workspace["replyReadiness"]["missingEnvVars"] == []
    assert workspace["ticketProof"]["kind"] == "support_ticket_operating_proof"
    assert workspace["ticketProof"]["ready"] is False
    assert workspace["ticketProof"]["summary"] == {
        "totalChecks": 8,
        "readyChecks": 7,
        "blockedChecks": 1,
        "blockedKeys": ["knowledge"],
    }
    proof_checks = {check["key"]: check for check in workspace["ticketProof"]["checks"]}
    assert proof_checks["source"]["ready"] is True
    assert proof_checks["source"]["detail"] == "channel:slack:support"
    assert proof_checks["assignee"]["ready"] is True
    assert proof_checks["workflow"]["detail"] == "Ticket is in ongoing."
    assert proof_checks["account"]["detail"] == "customer@example.com"
    assert proof_checks["knowledge"]["ready"] is False
    assert proof_checks["knowledge"]["action"] == "fill_knowledge"
    assert proof_checks["agent"]["ready"] is True
    assert proof_checks["reply_route"]["ready"] is True
    assert proof_checks["human_loop"]["ready"] is True


