    contact = {"id": "contact_existing", "contact_key": "customer@example.com", "email": "customer@example.com"}
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []
    automations: list[dict] = []

    def fake_first(collection: str, *_args, **_kwargs):
        if collection == "support_accounts":
            return account
        if collection == "support_contacts":
            return contact
        if collection == "support_issues":
            return existing
        return None

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(
        issues,
        "_list_all",
        lambda collection, *_args, **_kwargs: [{"latest_message_at": "2026-06-30T10:00:00Z"}]
        if collection == "support_issues"
        else [],
    )

    def fake_patch(path: str, data: dict) -> dict:
        patched.append((path, data))
        return {**existing, **data}

    monkeypatch.setattr(issues, "_patch", fake_patch)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
