def test_admin_get_issue_for_chat_creates_missing_issue_from_chat(monkeypatch):
    calls: list[tuple[str, object]] = []
    chat = {
        "id": "email-2",
        "email_id": "email-2",
        "metadata": {"source": "gmail", "threadId": "thread-1"},
    }
    created_issue = {"id": "issue1", "sourceEmailId": "email-thread:gmail:thread-1"}

    def fake_get_issue_by_chat_id(*_args, **_kwargs):
        calls.append(("lookup", _args[0]))
        return None

    def fake_get_chat(chat_id: str, **kwargs):
        calls.append(("chat", (chat_id, kwargs)))
        return chat

    def fake_upsert_issue_from_chat(next_chat: dict, **kwargs):
        calls.append(("upsert", (next_chat, kwargs)))
        return created_issue

    monkeypatch.setattr(admin_issue_api, "get_issue_by_chat_id", fake_get_issue_by_chat_id)
    monkeypatch.setattr(admin_issue_api, "get_chat", fake_get_chat)
    monkeypatch.setattr(admin_issue_api, "upsert_issue_from_chat", fake_upsert_issue_from_chat)

    result = asyncio.run(
        admin_issue_api.get_issue_for_chat(
            "email-2",
            SimpleNamespace(tenant_id="tenant1", project_id="project1", role="viewer"),
            SimpleNamespace(email="viewer@example.com"),
        )
    )

    assert result == created_issue
    assert calls[0] == ("lookup", "email-2")
    assert calls[1] == ("chat", ("email-2", {"tenant_id": "tenant1", "project_id": "project1"}))
    assert calls[2][0] == "upsert"
    assert calls[2][1][1]["source"] == "gmail"


