def test_ticket_creation_mode_accepts_product_aliases():
    per_message_channel = {"config": {"ticketCreationMode": "new_ticket_per_message"}}
    per_thread_channel = {"config": {"ticketCreationMode": "one_ticket_per_thread"}}

    assert issues._ticket_creation_mode(per_message_channel) == "per_message"
    assert issues._ticket_source_key(
        channel=per_message_channel,
        thread_id="thread-1",
        message_id="message-2",
    ) == "message-2"
    assert issues._ticket_creation_mode(per_thread_channel) == "per_thread"
    assert issues._ticket_source_key(
        channel=per_thread_channel,
        thread_id="thread-1",
        message_id="message-2",
    ) == "thread-1"
    assert issues._email_issue_source_id(
        email_id="message-2",
        source="addin",
        channel=per_message_channel,
        metadata={"threadId": "thread-1"},
    ) == "message-2"
    assert issues._email_issue_source_id(
        email_id="message-2",
        source="addin",
        channel=per_thread_channel,
        metadata={"threadId": "thread-1"},
    ) == "email-thread:addin:thread-1"


