def test_run_workflow_lifecycle_proof_creates_done_ticket_and_refreshes_counts(monkeypatch):
    created: list[dict] = []
    update_calls: list[dict] = []

    def fake_create_manual_issue(**kwargs):
        created.append(kwargs)
        return {"id": "issue-proof", "status": "open"}

    def fake_update_issue(issue_id: str, *, tenant_id: str | None, project_id: str, updates: dict):
        updates_record = {
            "issue_id": issue_id,
            "tenant_id": tenant_id,
            "project_id": project_id,
            "updates": updates,
        }
        update_calls.append(updates_record)
        return {"id": issue_id, "status": updates["status"], "assigneeEmail": "agent@example.com"}

    monkeypatch.setattr(admin_issue_api, "create_manual_issue", fake_create_manual_issue)
    monkeypatch.setattr(admin_issue_api, "update_issue", fake_update_issue)
    monkeypatch.setattr(
        admin_issue_api,
        "support_analytics",
        lambda **_kwargs: {
            "launchReadiness": {"status": "ready", "blockers": [], "warnings": [], "checks": 3},
            "workflowTransitionEvents": 2,
            "workflowOngoingTransitions": 1,
            "workflowDoneTransitions": 1,
            "successfulWorkflowLifecycleProofs": 1,
        },
    )

    result = admin_issue_api.run_workflow_lifecycle_proof(
        tenant_id="tenant1",
        project_id="project1",
        actor_email="Agent@Example.com",
    )

    assert created[0]["creator_email"] == "agent@example.com"
    assert created[0]["assignee_email"] == "agent@example.com"
    assert created[0]["run_automations"] is False
    assert [call["updates"]["status"] for call in update_calls] == ["ongoing", "done"]
    assert [call["updates"]["workflow_source"] for call in update_calls] == ["launch_proof", "launch_proof"]
    assert update_calls[0]["updates"]["tags"] == ["launch-proof", "workflow-proof"]
    assert result["issue"]["status"] == "done"
    assert result["successfulWorkflowLifecycleProofs"] == 1
    assert result["launchReadiness"]["status"] == "ready"


