def test_update_issue_records_assignment_capacity_override(monkeypatch):
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []

    def fake_first(collection, *_args, **_kwargs):
        if collection == "support_issues":
            return {
                "id": "issue1",
                "source_email_id": "email-1",
                "subject": "Capacity check",
                "status": "open",
                "priority": "normal",
                "assignee_email": "",
                "queue_key": "billing",
                "queue_name": "Billing",
            }
        if collection == "support_queues":
            return {
                "id": "queue1",
                "queue_key": "billing",
                "name": "Billing",
                "metadata": {
                    "assignmentMode": "least_open",
                    "allowedAssigneeEmails": ["owner@example.com"],
                    "ownerCapacity": 1,
                },
            }
        return None

    def fake_list_all(collection, *_args, **_kwargs):
        if collection == "support_issues":
            return [
                {
                    "id": "issue-busy",
                    "queue_key": "billing",
                    "status": "ongoing",
                    "assignee_email": "owner@example.com",
                },
                {
                    "id": "issue-done",
                    "queue_key": "billing",
                    "status": "done",
                    "assignee_email": "owner@example.com",
                },
            ]
        return []

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_list_all", fake_list_all)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)

    updated = issues.update_issue(
        "issue1",
        tenant_id="tenant1",
        project_id="project1",
        updates={
            "assignee_email": "owner@example.com",
            "assigned_by": "lead@example.com",
            "source": "manual_override",
        },
    )

    assert updated
    assert updated["assigneeEmail"] == "owner@example.com"
    assert patched == [
        (
            "/api/collections/support_issues/records/issue1",
            {"assignee_email": "owner@example.com"},
        )
    ]
    capacity_events = [
        data
        for path, data in posted
        if path == "/api/collections/support_issue_events/records"
        and data["event_type"] == "assignment_capacity_override"
    ]
    assert len(capacity_events) == 1
    event = capacity_events[0]
    assert event["actor_email"] == "lead@example.com"
    assert event["body"] == "owner@example.com assigned over 1 active ticket capacity"
    assert event["metadata"] == {
        "queueKey": "billing",
        "queueName": "Billing",
        "assigneeEmail": "owner@example.com",
        "activeTicketsBefore": 1,
        "activeTicketsAfter": 2,
        "capacity": 1,
        "overBy": 1,
        "fromAssignee": "",
        "toAssignee": "owner@example.com",
        "source": "manual_override",
        "actorEmail": "lead@example.com",
    }


