def test_run_sla_breach_escalations_records_event_and_runs_automation(monkeypatch):
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []
    automations: list[dict] = []

    def fake_list_all(collection: str, filter_str: str, **_kwargs):
        if collection == "support_sla_events":
            assert "status='pending'" in filter_str
            assert "target_at<" in filter_str
            return [
                {
                    "id": "sla1",
                    "issue": "issue1",
                    "event_type": "first_response_due",
                    "status": "pending",
                    "target_at": "2020-01-01T00:00:00+00:00",
                    "metadata": {"minutes": 30},
                },
                {
                    "id": "sla2",
                    "issue": "issue2",
                    "event_type": "resolution_due",
                    "status": "pending",
                    "target_at": "2020-01-01T00:00:00+00:00",
                    "metadata": {"escalatedAt": "2020-01-01T01:00:00+00:00"},
                },
                {
                    "id": "sla3",
                    "issue": "issue3",
                    "event_type": "resolution_due",
                    "status": "pending",
                    "target_at": "2999-01-01T00:00:00+00:00",
                    "metadata": {},
                },
            ]
        return []

    def fake_first(collection: str, *_args, **_kwargs):
        if collection == "support_issues":
            return {
                "id": "issue1",
                "status": "open",
                "priority": "high",
                "assignee_email": "",
            }
        return None

    monkeypatch.setattr(issues, "_list_all", fake_list_all)
    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(
        issues,
        "_run_automation_rules_for_issue",
        lambda **kwargs: automations.append(kwargs) or {"processed": 1, "failed": 0, "items": []},
    )

    result = issues.run_sla_breach_escalations_for_scope(
        tenant_id="tenant1",
        project_id="project1",
        actor_email="sla-monitor",
        source="test",
    )

    assert result["processed"] == 3
    assert result["escalated"] == 1
    assert result["skipped"] == 2
    assert result["failed"] == 0
    assert result["items"][0]["status"] == "escalated"
    assert result["items"][1]["reason"] == "already_escalated"
    assert result["items"][2]["reason"] == "not_overdue"
    assert patched[0][0] == "/api/collections/support_sla_events/records/sla1"
    assert patched[0][1]["metadata"]["escalatedBy"] == "sla-monitor"
    assert posted[0][0] == "/api/collections/support_issue_events/records"
    assert posted[0][1]["event_type"] == "sla_breached"
    assert posted[0][1]["title"] == "SLA breached: First response"
    assert automations[0]["trigger"] == "sla_breached"
    assert automations[0]["context"]["slaEventId"] == "sla1"


