def test_sync_account_insights_extracts_ticket_signal_evidence(monkeypatch):
    posted: list[tuple[str, dict]] = []
    patched: list[tuple[str, dict]] = []
    ids = iter(["summaryInsight", "riskInsight", "featureInsight"])
    issue = {
        "id": "issue1",
        "account": "account1",
        "status": "open",
        "priority": "normal",
        "subject": "Enterprise roadmap gap",
        "ai_summary": "Customer asks for a roadmap gap.",
        "activated_intent": "",
        "requires_human": False,
    }
    message_body = "Champion says renewal is at risk unless we add Slack integration and roadmap export."

    def fake_list_all(collection: str, *_args, **_kwargs):
        if collection == "support_issues":
            return [issue]
        return []

    def fake_first(collection: str, *_args, **_kwargs):
        if collection == "support_account_insights":
            return None
        return None

    monkeypatch.setattr(issues, "_list_all", fake_list_all)
    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "generate_id", lambda: next(ids))
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)

    issues._sync_account_insights(
        account_id="account1",
        issue=issue,
        messages=[{"body": message_body}],
        tenant_id="tenant1",
        project_id="project1",
    )

    assert patched[0] == ("/api/collections/support_accounts/records/account1", {"health_status": "active"})
    insight_posts = [data for path, data in posted if path == "/api/collections/support_account_insights/records"]
    assert [item["type"] for item in insight_posts] == ["summary", "risk", "feature_request"]
    risk = insight_posts[1]
    assert risk["title"] == "Renewal risk detected"
    assert risk["body"] == message_body
    assert risk["metadata"]["source"] == "issue_signal"
    assert risk["metadata"]["signalCategory"] == "renewal"
    assert risk["metadata"]["actionKind"] == "protect_renewal"
    assert "Brief the account owner" in risk["metadata"]["recommendedAction"]
    assert "at risk" in risk["metadata"]["matchedKeywords"]
    feature = insight_posts[2]
    assert feature["title"] == "Integration demand"
    assert feature["body"] == message_body
    assert feature["metadata"]["source"] == "issue_keyword"
    assert feature["metadata"]["signalCategory"] == "integration"
    assert {"roadmap", "integration"} <= set(feature["metadata"]["matchedKeywords"])


