def test_native_slack_bot_reply_uploads_base64_attachments(monkeypatch):
    calls: list[dict[str, object]] = []

    class FakeClient:
        def __init__(self, timeout: int):
            self.timeout = timeout

        def __enter__(self):
            return self

        def __exit__(self, *_args):
            return False

        def post(self, url: str, **kwargs):
            calls.append({"url": url, **kwargs})
            if url.endswith("/chat.postMessage"):
                return support_delivery.httpx.Response(
                    200,
                    json={"ok": True, "channel": "C123", "ts": "1710000001.000200"},
                    request=support_delivery.httpx.Request("POST", url),
                )
            if url.endswith("/files.getUploadURLExternal"):
                return support_delivery.httpx.Response(
                    200,
                    json={"ok": True, "upload_url": "https://files.slack.com/upload/v1/abc", "file_id": "F123"},
                    request=support_delivery.httpx.Request("POST", url),
                )
            if url == "https://files.slack.com/upload/v1/abc":
                return support_delivery.httpx.Response(
                    200,
                    text="OK - 3",
                    request=support_delivery.httpx.Request("POST", url),
                )
            if url.endswith("/files.completeUploadExternal"):
                return support_delivery.httpx.Response(
                    200,
                    json={"ok": True, "files": [{"id": "F123", "title": "quote.pdf"}]},
                    request=support_delivery.httpx.Request("POST", url),
                )
            raise AssertionError(f"unexpected Slack URL: {url}")

    monkeypatch.setattr(support_delivery.httpx, "Client", FakeClient)

    result = support_delivery.send_support_channel_reply(
        message_id="reply123",
        channel="slack",
        channel_config={"outboundTransport": "bot"},
        to_address="slack:T123:U123",
        from_address="agent@example.com",
        subject="Re: Slack ticket",
        body="Slack reply.",
        metadata={
            "channelId": "C123",
            "threadTs": "1710000000.000100",
            "attachments": [{"filename": "quote.pdf", "base64": "cGRm", "contentType": "application/pdf"}],
        },
        secrets={"SUPPORT_SLACK_BOT_TOKEN": "xoxb-token"},
    )

    assert result.status == "sent"
    assert result.provider_message_id == "slack:C123:1710000001.000200;slack_file:F123"
    assert calls[0]["json"]["text"] == "Slack reply."
    assert calls[1]["data"] == {"filename": "quote.pdf", "length": "3"}
    assert calls[2]["content"] == b"pdf"
    assert calls[2]["headers"] == {"Content-Type": "application/pdf"}
    assert calls[3]["json"] == {
        "files": [{"id": "F123", "title": "quote.pdf"}],
        "channel_id": "C123",
        "thread_ts": "1710000000.000100",
    }
    assert result.metadata["attachmentDelivery"]["uploaded"] == 1
    assert result.metadata["attachmentDelivery"]["items"][0]["providerFileId"] == "F123"


