def test_create_issue_agent_answer_can_answer_without_draft(monkeypatch):
    posted: list[tuple[str, dict]] = []
    stored_usage: list[tuple[list[dict], dict]] = []
    ids = iter(["aiRun123", "event123"])
    issue = {
        "id": "issue1",
        "channel": "email",
        "source": "email:addin",
        "contactEmail": "customer@example.com",
        "subject": "API outage",
        "aiSummary": "Customer reports API outage",
        "messages": [
            {
                "id": "msg1",
                "direction": "customer",
                "body": "Production API is down and customers cannot log in.",
            }
        ],
    }

    def fail_create_reply(*_args, **_kwargs):
        raise AssertionError("ask-only agent answer must not create a reply")

    monkeypatch.setattr(issues, "generate_id", lambda: next(ids))
    monkeypatch.setattr(issues, "get_issue", lambda *_args, **_kwargs: issue)
    monkeypatch.setattr(issues, "_list_all", lambda *_args, **_kwargs: [])
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "create_issue_reply", fail_create_reply)
    monkeypatch.setattr(
        pb_client,
        "store_llm_usage_events",
        lambda calls, **kwargs: stored_usage.append((calls, kwargs)),
    )

    def fake_draft_issue_agent_answer(**_kwargs):
        collector = usage_module.current_collector()
        assert collector is not None
        collector.add(
            {
                "stage": "issue_agent_answer",
                "provider": "test-provider",
                "model": "test-model",
                "inputTokens": 8,
                "outputTokens": 3,
                "cachedInputTokens": 0,
                "totalTokens": 11,
                "metadataAvailable": True,
            }
        )
        return IssueAgentDraft(
            answer="Ask-only answer from ticket context.",
            confidence="medium",
            generation_mode="llm",
        )

    monkeypatch.setattr(issues, "draft_issue_agent_answer", fake_draft_issue_agent_answer)

    result = issues.create_issue_agent_answer(
        "issue1",
        tenant_id="tenant1",
        project_id="project1",
        author_email="agent@example.com",
        question="What is the next step?",
        create_draft=False,
        use_knowledge_agent=True,
    )

    assert result is not None
    assert result["reply"] is None
    assert result["approvalRequired"] is False
    assert result["generationMode"] == "llm"
    assert result["run"]["status"] == "success"
    assert result["run"]["requiresHuman"] is False
    assert result["run"]["metadata"]["replyId"] == ""
    assert result["run"]["metadata"]["question"] == "What is the next step?"
    assert result["run"]["metadata"]["generationMode"] == "llm"
    assert result["run"]["tokenUsage"]["inputTokens"] == 8
    assert result["run"]["tokenUsage"]["outputTokens"] == 3
    assert result["run"]["tokenUsage"]["totalTokens"] == 11
    assert result["run"]["tokenUsage"]["calls"][0]["stage"] == "issue_agent_answer"
    assert len(stored_usage) == 1
    assert stored_usage[0][0][0]["stage"] == "issue_agent_answer"
    assert stored_usage[0][1] == {
        "tenant_id": "tenant1",
        "project_id": "project1",
        "run_id": "aiRun123",
    }
    assert not any(path == "/api/collections/support_outbound_messages/records" for path, _data in posted)
    gap = next(data for path, data in posted if path == "/api/collections/support_knowledge_gaps/records")
    assert result["knowledgeGap"]["id"] == "event123"
    assert result["knowledgeGap"]["metadata"]["source"] == "agent_answer"
    assert result["knowledgeGap"]["metadata"]["weakSignals"] == ["no_citations"]
    assert result["knowledgeGap"]["metadata"]["aiRunId"] == "aiRun123"
    assert gap["metadata"]["question"] == "What is the next step?"
    assert gap["metadata"]["citationCount"] == 0
    event = next(data for path, data in posted
                 if path == "/api/collections/support_issue_events/records"
                 and data["event_type"] == "agent_answer_prepared")
    assert event["metadata"]["replyId"] == ""
    assert event["metadata"]["aiRunId"] == "aiRun123"
    assert event["metadata"]["knowledgeGapId"] == "event123"
    assert event["metadata"]["weakKnowledgeSignals"] == ["no_citations"]


