def test_agent_answer_usage_sink_deduplicates_late_usage_before_bind(monkeypatch):
    patched: list[tuple[str, dict]] = []
    stored_usage: list[tuple[list[dict], dict]] = []
    call = {
        "stage": "issue_automation_answer",
        "inputTokens": 8,
        "outputTokens": 3,
        "totalTokens": 11,
        "metadataAvailable": True,
    }
    monkeypatch.setattr(
        issues,
        "_patch",
        lambda path, data: patched.append((path, data)) or data,
    )
    monkeypatch.setattr(
        pb_client,
        "store_llm_usage_events",
        lambda calls, **kwargs: stored_usage.append((calls, kwargs)),
    )
    sink = issues._AgentAnswerUsageSink(tenant_id="tenant1", project_id="project1")

    sink.report_late([call])
    sink.bind(run_id="run1", initial_calls=[call])

    assert len(patched) == 1
    assert patched[0][0] == "/api/collections/support_ai_runs/records/run1"
    assert patched[0][1]["token_usage"]["totalTokens"] == 11
    assert len(patched[0][1]["token_usage"]["calls"]) == 1
    assert len(stored_usage) == 1
    assert stored_usage[0][0] == [call]


def test_agent_answer_usage_sink_patches_only_new_late_usage_after_bind(monkeypatch):
    patched: list[tuple[str, dict]] = []
    stored_usage: list[tuple[list[dict], dict]] = []
    initial_call = {
        "stage": "issue_automation_answer",
        "inputTokens": 8,
        "outputTokens": 3,
        "totalTokens": 11,
        "metadataAvailable": True,
    }
    late_call = {
        "stage": "issue_automation_grounding",
        "inputTokens": 5,
        "outputTokens": 2,
        "totalTokens": 7,
        "metadataAvailable": True,
    }
    monkeypatch.setattr(
        issues,
        "_patch",
        lambda path, data: patched.append((path, data)) or data,
    )
    monkeypatch.setattr(
        pb_client,
        "store_llm_usage_events",
        lambda calls, **kwargs: stored_usage.append((calls, kwargs)),
    )
    sink = issues._AgentAnswerUsageSink(tenant_id="tenant1", project_id="project1")

    sink.bind(run_id="run1", initial_calls=[initial_call])
    sink.report_late([initial_call, late_call])

    assert len(patched) == 1
    assert patched[0][1]["token_usage"]["totalTokens"] == 18
    assert [call["stage"] for call in patched[0][1]["token_usage"]["calls"]] == [
        "issue_automation_answer",
        "issue_automation_grounding",
    ]
    assert [batch for batch, _kwargs in stored_usage] == [[initial_call], [late_call]]


@pytest.mark.parametrize(
    "gate",
    [
        {
            "verified": False,
            "status": "failed",
            "answerSha256": grounding_text_sha256("answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"}
            ],
            "obligationAssessments": [
                {"obligationId": "concern-new:obligation-1", "covered": True}
            ],
        },
        {
            "verified": True,
            "status": "passed",
            "answerSha256": grounding_text_sha256("answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"},
                {"id": "concern-new:obligation-2", "concernId": "concern-new"},
            ],
            "obligationAssessments": [
                {"obligationId": "concern-new:obligation-1", "covered": True}
            ],
        },
        {
            "verified": True,
            "status": "passed",
            "answerSha256": grounding_text_sha256("answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"}
            ],
            "obligationAssessments": [
                {"obligationId": "concern-new:obligation-1", "covered": True},
                {"obligationId": "concern-new:obligation-1", "covered": True},
            ],
        },
        {
            "verified": True,
            "status": "passed",
            "answerSha256": grounding_text_sha256("answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"},
                {"id": "concern-malformed:obligation-1"},
            ],
            "obligationAssessments": [
                {"obligationId": "concern-new:obligation-1", "covered": True}
            ],
        },
        {
            "verified": True,
            "status": "passed",
            "answerSha256": grounding_text_sha256("another answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"}
            ],
            "obligationAssessments": [
                {
                    "obligationId": "concern-new:obligation-1",
                    "covered": True,
                    "resolution": "answered",
                }
            ],
        },
        {
            "verified": True,
            "status": "passed",
            "answerSha256": grounding_text_sha256("answer"),
            "answerObligations": [
                {"id": "concern-new:obligation-1", "concernId": "concern-new"}
            ],
            "obligationAssessments": [
                {
                    "obligationId": "concern-new:obligation-1",
                    "covered": True,
                    "resolution": "not_covered",
                }
            ],
        },
    ],
)
def test_effective_grounding_coverage_rejects_unverified_partial_or_duplicate_gate(
    gate: dict,
) -> None:
    concerns, obligations, source = issues._effective_grounding_coverage(
        grounding_gate=gate,
        expected_answer_sha256=grounding_text_sha256("answer"),
        composer_concern_ids=("concern-composer",),
        composer_obligation_ids=("concern-composer:obligation-1",),
    )

    assert concerns == ("concern-composer",)
    assert obligations == ("concern-composer:obligation-1",)
    assert source == "composer"


def test_effective_grounding_coverage_uses_none_without_any_valid_source() -> None:
    concerns, obligations, source = issues._effective_grounding_coverage(
        grounding_gate={},
        expected_answer_sha256=grounding_text_sha256("answer"),
        composer_concern_ids=(),
        composer_obligation_ids=(),
    )

    assert concerns == ()
    assert obligations == ()
    assert source == "none"


