def test_knowledge_suggestions_rank_title_tags_and_explain_match(monkeypatch):
    articles = [
        {
            "id": "generic",
            "title": "General support checklist",
            "body": "Ask for logs and confirm customer impact.",
            "status": "published",
            "tags": ["support"],
            "updated": "2026-07-01T10:00:00Z",
        },
        {
            "id": "api",
            "title": "API outage runbook",
            "body": "Check incident owner, status page, and production API error rate.",
            "status": "published",
            "tags": ["api", "incident"],
            "updated": "2026-07-01T09:00:00Z",
        },
        {
            "id": "billing",
            "title": "Billing invoice help",
            "body": "Invoices and card updates.",
            "status": "published",
            "tags": ["billing"],
            "updated": "2026-07-01T11:00:00Z",
        },
    ]

    monkeypatch.setattr(
        issues,
        "_list_all",
        lambda collection, *_args, **_kwargs: articles if collection == "knowledge_articles" else [],
    )

    suggestions = issues._knowledge_suggestions_for_issue(
        {
            "id": "issue1",
            "subject": "Production API outage",
            "activatedIntent": "api_outage",
            "aiSummary": "Customer reports a production API incident.",
        },
        [{"direction": "customer", "body": "The API is down and customers cannot log in."}],
        tenant_id="tenant1",
        project_id="project1",
        question="What should we answer during the incident?",
        limit=3,
    )

    assert [article["id"] for article in suggestions] == ["api"]
    match = suggestions[0]["metadata"]["knowledgeMatch"]
    assert match["score"] > 0
    assert "title" in match["signals"]
    assert "tags" in match["signals"]
    assert {"api", "incident", "outage"} & set(match["matchedTerms"])


