def _grounded_automatic_reply(
    article: dict,
    *,
    body: str = "Grounded automatic answer.",
) -> tuple[dict, dict]:
    article = {
        **article,
        "metadata": {
            "visibility": "public",
            "public": True,
            "automationAllowed": True,
            **(article.get("metadata") if isinstance(article.get("metadata"), dict) else {}),
        },
    }
    normalized_article = issues._normalize_article(article)
    _, snapshot = grounding_evidence_snapshot(normalized_article)
    body_sha256 = grounding_text_sha256(body)
    context_snapshots = grounding_context_snapshots(issue={"id": "issue1"}, messages=[])
    gate = {
        "version": issues.GROUNDING_GATE_VERSION,
        "verified": True,
        "status": "passed",
        "checkedAt": datetime.now(timezone.utc).isoformat(),
        "answerSha256": body_sha256,
        "deliveryBodySha256": body_sha256,
        "citationIds": [normalized_article["id"]],
        "evidenceSnapshots": [snapshot],
        "contextSnapshots": list(context_snapshots),
    }
    reply = {
        "id": "reply123",
        "issue": "issue1",
        "channel": "email",
        "to_address": "customer@example.com",
        "from_address": "automation@example.com",
        "subject": "Re: Need help",
        "body": body,
        "status": "queued",
        "metadata": {
            "source": "agent_answer",
            "autoSend": True,
            "approvalRequired": False,
            "approved": True,
            "groundingVerified": True,
            "groundingGate": gate,
            "deliveryBodySha256": body_sha256,
        },
    }
    return reply, normalized_article


@pytest.mark.parametrize(
    "lifecycle_fields",
    [
        {"status": "done"},
        {"status": "closed"},
        {"status": "open", "mergedIntoIssueId": "issue2"},
    ],
)
def test_create_automatic_reply_rejects_terminal_or_merged_ticket(
    monkeypatch,
    lifecycle_fields,
):
    reply, _article = _grounded_automatic_reply(
        {
            "id": "article1",
            "title": "Current policy",
            "body": "The policy supports this answer.",
            "status": "published",
            "metadata": {"reviewStatus": "reviewed"},
        }
    )
    issue = {
        "id": "issue1",
        "channel": "email",
        "contactEmail": "customer@example.com",
        "subject": "Need help",
        "assigneeEmail": "automation@example.com",
        **lifecycle_fields,
    }
    posted: list[tuple[str, dict]] = []
    updates: list[dict] = []
    monkeypatch.setattr(issues, "get_issue", lambda *_args, **_kwargs: issue)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(
        issues,
        "update_issue",
        lambda _issue_id, **kwargs: updates.append(kwargs) or issue,
    )

    with pytest.raises(ValueError, match="active unmerged ticket"):
        issues.create_issue_reply(
            "issue1",
            tenant_id="tenant1",
            project_id="project1",
            author_email="automation@example.com",
            body=reply["body"],
            status="queued",
            source="agent_answer",
            metadata=reply["metadata"],
        )

