def test_automatic_grounding_binding_allows_trusted_feedback_footer() -> None:
    raw_article = {
        "id": "article1",
        "title": "Current policy",
        "body": "The policy supports this answer.",
        "status": "published",
        "metadata": {"reviewStatus": "reviewed"},
    }
    source_body = "Grounded automatic answer."
    delivery_body = f"{source_body}\n\nHow did we do? https://example.test/feedback"
    reply, _article = _grounded_automatic_reply(raw_article, body=source_body)

    metadata = issues._bind_automatic_grounding_metadata(
        reply["metadata"],
        source_body=source_body,
        delivery_body=delivery_body,
    )

    assert metadata["groundingGate"]["answerSha256"] == grounding_text_sha256(source_body)
    assert metadata["deliveryBodySha256"] == grounding_text_sha256(delivery_body)
    assert metadata["groundingGate"]["deliveryBodySha256"] == grounding_text_sha256(
        delivery_body
    )
    with pytest.raises(ValueError, match="no valid grounding binding"):
        issues._bind_automatic_grounding_metadata(
            reply["metadata"],
            source_body="Different unevaluated answer.",
            delivery_body=delivery_body,
        )


