@pytest.mark.parametrize(
    ("mutation", "expected_reason"),
    [
        ("missing", "grounding_evidence_unavailable"),
        ("body", "grounding_evidence_changed"),
        ("unpublished", "grounding_evidence_unpublished"),
        ("stale", "grounding_evidence_stale"),
    ],
)
def test_automatic_grounding_delivery_binding_rejects_changed_evidence(
    monkeypatch,
    mutation,
    expected_reason,
):
    raw_article = {
        "id": "article1",
        "title": "Current policy",
        "body": "The policy supports this answer.",
        "status": "published",
        "tags": ["policy"],
        "metadata": {"reviewStatus": "reviewed", "revision": 3},
        "updated": "2026-07-15T08:00:00Z",
    }
    reply, article = _grounded_automatic_reply(raw_article)
    current_article = dict(article)
    if mutation == "missing":
        current_article = None
    elif mutation == "body":
        current_article["body"] = "Changed policy body."
    elif mutation == "unpublished":
        current_article["status"] = "draft"
    else:
        current_article["reviewStatus"] = "stale"
        current_article["freshnessStatus"] = "stale"
        current_article["needsReview"] = True
    monkeypatch.setattr(
        issues,
        "get_knowledge_article",
        lambda *_args, **_kwargs: current_article,
    )
    monkeypatch.setattr(
        issues,
        "get_issue",
        lambda *_args, **_kwargs: {"id": "issue1", "messages": []},
    )

    reason = issues._automatic_grounding_delivery_blocked_reason(
        reply,
        tenant_id="tenant1",
        project_id="project1",
    )

    assert reason == expected_reason


