def test_slack_channel_ticket_reply_lifecycle_uses_real_resolver_and_approval_gate(monkeypatch):
    id_counter = {"value": 0}
    records: dict[str, list[dict]] = {
        "support_channels": [{
            "id": "channel1",
            "tenant": "tenant1",
            "project": "project1",
            "channel_key": "slack-main",
            "type": "slack",
            "name": "Slack",
            "status": "active",
            "config": {
                "teamId": "T123",
                "ticketCreationMode": "per_message",
                "outboundWebhookUrl": "https://adapter.example/slack",
            },
        }],
    }
    sent: list[dict] = []

    def next_id() -> str:
        id_counter["value"] += 1
        return f"record{id_counter['value']}"

    def collection_from_path(path: str) -> tuple[str, str]:
        collection = path.split("/api/collections/", 1)[1].split("/records", 1)[0]
        record_id = path.rsplit("/", 1)[-1] if not path.endswith("/records") else ""
        return collection, record_id

    def filter_values(filter_str: str) -> dict[str, str]:
        values: dict[str, str] = {}
        for chunk in filter_str.replace("(", " ").replace(")", " ").split("&&"):
            clean = chunk.strip()
            if "='" in clean:
                key, rest = clean.split("='", 1)
                values[key.strip()] = rest.split("'", 1)[0]
            elif "=" in clean and not any(operator in clean for operator in ("!=", ">=", "<=", ">", "<")):
                key, value = clean.split("=", 1)
                values[key.strip()] = value.strip().strip("'")
        return values

    def matches_filter(record: dict, filter_str: str) -> bool:
        for key, value in filter_values(filter_str).items():
            current = record.get(key)
            if isinstance(current, bool):
                current_value = "true" if current else "false"
            else:
                current_value = "" if current is None else str(current)
            if current_value != value:
                return False
        return True

    def fake_list_all(collection: str, filter_str: str = "", **_kwargs):
        return [
            record
            for record in records.get(collection, [])
            if not filter_str or matches_filter(record, filter_str)
        ]

    def fake_first(collection: str, filter_str: str = "", **kwargs):
        items = fake_list_all(collection, filter_str, **kwargs)
        return items[0] if items else None

    def fake_post(path: str, data: dict):
        collection, _record_id = collection_from_path(path)
        stored = dict(data)
        stored.setdefault("id", next_id())
        records.setdefault(collection, []).append(stored)
        return stored

    def fake_patch(path: str, data: dict):
        collection, record_id = collection_from_path(path)
        for record in records.setdefault(collection, []):
            if record.get("id") == record_id:
                record.update(data)
                return record
        created = {"id": record_id, **data}
        records[collection].append(created)
        return created

    monkeypatch.setattr(issues, "generate_id", next_id)
    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_list_all", fake_list_all)
    monkeypatch.setattr(issues, "_post", fake_post)
    monkeypatch.setattr(issues, "_patch", fake_patch)
    monkeypatch.setattr(issues, "get_chat", lambda *_args, **_kwargs: None)
    monkeypatch.setattr(issues, "_ensure_issue_sla_events", lambda **_kwargs: None)
    monkeypatch.setattr(issues, "load_runtime_secrets", lambda *_args, **_kwargs: {})
    monkeypatch.setattr(
        issues,
        "send_support_channel_reply",
        lambda **kwargs: sent.append(kwargs) or DeliveryResult(
            status="sent",
            provider="slack_webhook",
            provider_message_id="slack:C123:1710000000.000200",
            metadata={
                "deliveryRoute": {
                    "provider": "slack_webhook",
                    "channel": "slack",
                    "transport": "webhook",
                    "targetUrl": "https://adapter.example/slack",
                    "channelId": "C123",
                    "threadTs": "1710000000.000100",
                },
                "providerResponse": {"statusCode": 200, "body": {"ok": True}},
            },
        ),
    )

    inbound = issues.ingest_slack_event(
        "slack-main",
        tenant_id="tenant1",
        project_id="project1",
        payload={
            "team_id": "T123",
            "event_id": "Ev1",
            "event": {
                "type": "message",
                "channel": "C123",
                "user": "U456",
                "text": "Production API is down.",
                "ts": "1710000000.000100",
                "thread_ts": "1710000000.000100",
            },
        },
    )

    assert inbound["status"] == "success"
    issue_id = inbound["issueId"]
    assert issue_id == records["support_issues"][0]["id"]
    assert inbound["resolver"]["resolverAction"] == "created"
    assert inbound["resolver"]["ticketCreationMode"] == "per_message"
    assert inbound["resolver"]["externalTicketKey"].endswith(":1710000000.000100")
    issue_record = records["support_issues"][0]
    assert issue_record["source_email_id"] == "slack:T123:C123:1710000000.000100"
    assert issue_record["channel"] == "slack"
    assert issue_record["status"] == "open"
    timeline_message = records["support_messages"][0]
    assert timeline_message["source_message_id"] == "slack:T123:C123:1710000000.000100"
    assert timeline_message["metadata"]["resolver"]["sourceIssueId"] == issue_record["source_email_id"]

    reply = issues.create_issue_reply(
        issue_id,
        tenant_id="tenant1",
        project_id="project1",
        author_email="agent@example.com",
        body="We are checking this now.",
        status="queued",
        metadata={"approvalRequired": True, "approved": False, "reviewStatus": "pending"},
    )

    assert reply is not None
    reply_id = reply["id"]
    assert reply["status"] == "queued"
    assert reply["toAddress"] == "C123"
    assert reply["metadata"]["approvalRequired"] is True
    assert reply["metadata"]["replyTarget"] == {
        "channel": "slack",
        "key": "channelId",
        "value": "C123",
        "label": "Channel: C123",
        "channelKey": "slack-main",
    }
    assert records["support_issues"][0]["status"] == "ongoing"
    assert records["support_issues"][0]["assignee_email"] == "agent@example.com"

    try:
        issues.deliver_issue_reply(issue_id, reply_id, tenant_id="tenant1", project_id="project1")
    except ValueError as exc:
        assert "requires approval" in str(exc)
    else:
        raise AssertionError("Expected pending approval reply delivery to be blocked")

    approved = issues.approve_issue_reply(
        issue_id,
        reply_id,
        tenant_id="tenant1",
        project_id="project1",
        approved_by="lead@example.com",
    )
    delivered = issues.deliver_issue_reply(issue_id, reply_id, tenant_id="tenant1", project_id="project1")

    assert approved is not None
    assert approved["metadata"]["reviewStatus"] == "approved"
    assert delivered is not None
    assert delivered["status"] == "sent"
    assert delivered["provider"] == "slack_webhook"
    assert delivered["providerMessageId"] == "slack:C123:1710000000.000200"
    assert sent[0]["channel"] == "slack"
    assert sent[0]["to_address"] == "C123"
    assert sent[0]["metadata"]["channelKey"] == "slack-main"
    assert sent[0]["metadata"]["threadTs"] == "1710000000.000100"
    outbound_timeline = next(
        record
        for record in records["support_messages"]
        if record["direction"] == "agent"
    )
    assert outbound_timeline["metadata"]["providerMessageId"] == "slack:C123:1710000000.000200"
    assert outbound_timeline["metadata"]["deliveryRoute"]["targetUrl"] == "https://adapter.example/slack"
    event_types = [record["event_type"] for record in records["support_issue_events"]]
    assert "slack_message_received" in event_types
    assert "reply_queued" in event_types
    assert "reply_approved" in event_types
    assert "reply_sent" in event_types


