def test_deliver_issue_reply_defers_transient_channel_failure(monkeypatch):
    posted: list[tuple[str, dict]] = []
    patched: list[tuple[str, dict]] = []
    ids = iter(["message123", "event123", "notification123"])
    monkeypatch.setattr(issues, "generate_id", lambda: next(ids))

    def fake_first(collection: str, *_args, **_kwargs):
        if collection == "support_outbound_messages":
            return {
                "id": "reply123",
                "issue": "issue1",
                "channel": "slack",
                "to_address": "slack:T123:U123",
                "from_address": "agent@example.com",
                "subject": "Re: Need help",
                "body": "Reply body",
                "status": "queued",
                "metadata": {"issueSource": "slack-main", "deliveryAttempts": 2},
            }
        if collection == "support_messages":
            return None
        if collection == "support_channels":
            return {
                "id": "channel1",
                "channel_key": "slack-main",
                "type": "slack",
                "status": "active",
                "config": {"outboundWebhookUrl": "https://adapter.example/slack"},
            }
        return None

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(
        issues,
        "send_support_channel_reply",
        lambda **_kwargs: DeliveryResult(
            status="queued",
            provider="slack_webhook",
            error="HTTP 429: too_many_requests",
            retry_after_seconds=90,
        ),
    )

    reply = issues.deliver_issue_reply("issue1", "reply123", tenant_id="tenant1", project_id="project1")

    assert reply is not None
    assert reply["status"] == "queued"
    assert reply["error"] == "HTTP 429: too_many_requests"
    reply_patch = next(data for path, data in patched if path == "/api/collections/support_outbound_messages/records/reply123")
    assert reply_patch["status"] == "queued"
    assert reply_patch["metadata"]["deliveryAttempts"] == 3
    assert reply_patch["metadata"]["retryAfterSeconds"] == 90
    assert reply_patch["metadata"]["lastTransientError"] == "HTTP 429: too_many_requests"
    assert reply_patch["metadata"]["nextAttemptAt"]
    event_post = next(data for path, data in posted if path == "/api/collections/support_issue_events/records")
    assert event_post["event_type"] == "reply_deferred"
    assert event_post["title"] == "Reply deferred"
    assert not any(path == "/api/collections/support_messages/records" for path, _data in posted)


