def test_delivery_run_history(monkeypatch):
    posted: list[tuple[str, dict]] = []
    monkeypatch.setattr(issues, "generate_id", lambda: "deliveryRun123")
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(
        issues,
        "_list_all",
        lambda *_args, **_kwargs: [
            {
                "id": "deliveryRun123",
                "source": "scheduler",
                "status": "success",
                "processed": 2,
                "sent": 2,
                "failed": 0,
                "result": {"sent": 2},
                "started_at": "2026-07-01T10:00:00Z",
                "completed_at": "2026-07-01T10:01:00Z",
            }
        ],
    )

    run = issues.record_delivery_run(
        tenant_id="tenant1",
        project_id="project1",
        source="scheduler",
        result={"status": "success", "processed": 2, "sent": 2, "failed": 0},
        started_at="2026-07-01T10:00:00Z",
        completed_at="2026-07-01T10:01:00Z",
    )
    runs = issues.list_delivery_runs(tenant_id="tenant1", project_id="project1")

    assert run["id"] == "deliveryRun123"
    assert run["sent"] == 2
    assert posted[0][0] == "/api/collections/support_delivery_runs/records"
    assert posted[0][1]["source"] == "scheduler"
    assert runs[0]["status"] == "success"
    assert runs[0]["result"] == {"sent": 2}


def test_launch_proof_run_history(monkeypatch):
    posted: list[tuple[str, dict]] = []
    monkeypatch.setattr(issues, "generate_id", lambda: "proofRun123")
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(
        issues,
        "_list_all",
        lambda *_args, **_kwargs: [
            {
                "id": "proofRun123",
                "status": "needs_attention",
                "ran": 2,
                "failed": 1,
                "skipped": 1,
                "actions": [
                    {"key": "email_sync", "label": "Email sync", "status": "success", "error": "", "result": {}},
                    {"key": "delivery", "label": "Delivery", "status": "failed", "error": "SMTP blocked", "result": {}},
                ],
                "launch_readiness": {"status": "needs_attention", "blockers": [], "warnings": [], "checks": 1},
                "launch_proof": {"status": "needs_attention", "channels": {"items": []}},
                "result": {"ran": 2},
                "started_at": "2026-07-01T10:00:00Z",
                "completed_at": "2026-07-01T10:01:00Z",
            }
        ],
    )

    result = {
        "actions": [
            {"key": "email_sync", "label": "Email sync", "status": "success", "error": "", "result": {}},
            {"key": "delivery", "label": "Delivery", "status": "failed", "error": "SMTP blocked", "result": {}},
            {"key": "channel_config", "label": "Channel config", "status": "skipped", "error": "", "result": {}},
        ],
        "ran": 2,
        "failed": 1,
        "skipped": 1,
        "launchReadiness": {"status": "needs_attention", "blockers": [], "warnings": [], "checks": 1},
        "launchProof": {"status": "needs_attention", "channels": {"items": []}},
    }
    run = issues.record_launch_proof_run(
        tenant_id="tenant1",
        project_id="project1",
        result=result,
        started_at="2026-07-01T10:00:00Z",
        completed_at="2026-07-01T10:01:00Z",
    )
    runs = issues.list_launch_proof_runs(tenant_id="tenant1", project_id="project1")

    assert run["id"] == "proofRun123"
    assert run["ran"] == 2
    assert run["failed"] == 1
    assert run["error"] == "SMTP blocked"
    assert posted[0][0] == "/api/collections/support_launch_proof_runs/records"
    assert posted[0][1]["launch_readiness"]["status"] == "needs_attention"
    assert posted[0][1]["actions"][1]["error"] == "SMTP blocked"
    assert runs[0]["launchReadiness"]["status"] == "needs_attention"
    assert runs[0]["launchProof"]["status"] == "needs_attention"


