def test_approve_issue_action_execution_applies_priority_change(monkeypatch):
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []
    updates: list[dict] = []
    rec = {
        "id": "action123",
        "issue": "issue1",
        "action_key": "raise_priority",
        "label": "Raise priority",
        "type": "automation",
        "status": "pending",
        "requested_by": "automation",
        "result": {"proposedAction": {"type": "set_priority", "priority": "urgent"}},
        "metadata": {"approvalRequired": True, "reviewStatus": "pending"},
        "started_at": "2026-07-01T10:00:00Z",
    }

    def fake_first(collection: str, *_args, **_kwargs):
        return rec if collection == "support_action_executions" else None

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "update_issue", lambda _issue_id, **kwargs: updates.append(kwargs["updates"]) or {"id": "issue1", "priority": "urgent"})
    monkeypatch.setattr(issues, "get_issue", lambda *_args, **_kwargs: {"id": "issue1", "priority": "urgent"})

    result = issues.approve_issue_action_execution(
        "issue1",
        "action123",
        tenant_id="tenant1",
        project_id="project1",
        approved_by="agent@example.com",
    )

    assert result is not None
    assert result["execution"]["status"] == "success"
    assert result["execution"]["metadata"]["reviewStatus"] == "approved"
    assert result["execution"]["result"]["application"] == {"applied": True, "type": "set_priority", "priority": "urgent"}
    assert result["issue"] == {"id": "issue1", "priority": "urgent"}
    assert updates == [{"priority": "urgent", "actor_email": "agent@example.com", "skip_automations": True}]
    assert patched[0][1]["status"] == "success"
    assert posted[0][1]["event_type"] == "action_approved"


