def test_approval_summary_counts_pending_action_executions(monkeypatch):
    def fake_list_all(collection: str, *_args, **_kwargs):
        if collection == "support_outbound_messages":
            return []
        if collection == "support_action_executions":
            return [
                {
                    "id": "action123",
                    "issue": "issue1",
                    "status": "pending",
                    "metadata": {"approvalRequired": True, "reviewStatus": "pending"},
                },
                {
                    "id": "action456",
                    "issue": "issue1",
                    "status": "skipped",
                    "metadata": {"approvalRequired": True, "reviewStatus": "rejected"},
                },
            ]
        return []

    monkeypatch.setattr(issues, "_list_all", fake_list_all)

    summary = issues._approval_summary_by_issue(
        ["issue1"],
        tenant_id="tenant1",
        project_id="project1",
    )

    assert summary["issue1"]["pendingApprovalCount"] == 1
    assert summary["issue1"]["hasPendingApproval"] is True
    assert summary["issue1"]["pendingReplyApprovalCount"] == 0
    assert summary["issue1"]["hasPendingReplyApproval"] is False
    assert summary["issue1"]["pendingActionApprovalCount"] == 1
    assert summary["issue1"]["hasPendingActionApproval"] is True


