def test_upsert_sla_policy_creates_and_updates(monkeypatch):
    posted: list[tuple[str, dict]] = []
    patched: list[tuple[str, dict]] = []
    existing = {
        "id": "slaPolicy123",
        "name": "Default",
        "active": True,
        "first_response_minutes": 240,
        "resolution_minutes": 2880,
    }

    def fake_first(_collection: str, filter_str: str):
        if "id='slaPolicy123'" in filter_str:
            return existing
        return None

    monkeypatch.setattr(issues, "generate_id", lambda: "slaPolicy123")
    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)

    created = issues.upsert_sla_policy(
        tenant_id="tenant1",
        project_id="project1",
        first_response_minutes=30,
        resolution_minutes=1440,
    )
    updated = issues.upsert_sla_policy(
        tenant_id="tenant1",
        project_id="project1",
        policy_id="slaPolicy123",
        name="Enterprise",
        active=True,
        first_response_minutes=60,
        resolution_minutes=240,
    )

    assert created["id"] == "slaPolicy123"
    assert created["firstResponseMinutes"] == 30
    assert posted[0][0] == "/api/collections/support_sla_policies/records"
    assert posted[0][1]["tenant"] == "tenant1"
    assert posted[0][1]["project"] == "project1"
    assert updated["name"] == "Enterprise"
    assert updated["resolutionMinutes"] == 240
    assert patched[0][0] == "/api/collections/support_sla_policies/records/slaPolicy123"


