def test_create_customer_portal_session_hashes_token(monkeypatch):
    posted: list[tuple[str, dict]] = []
    ids = iter(["portal123", "event123"])

    monkeypatch.setattr(issues, "generate_id", lambda: next(ids))
    monkeypatch.setattr(issues.secrets, "token_urlsafe", lambda _size: "portal-token")
    monkeypatch.setattr(issues, "get_issue", lambda *_args, **_kwargs: {"id": "issue1"})
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)

    session = issues.create_customer_portal_session(
        "issue1",
        tenant_id="tenant1",
        project_id="project1",
        created_by="agent@example.com",
        expires_hours=24,
    )

    assert session is not None
    assert session["id"] == "portal123"
    assert session["token"] == "portal-token"
    portal_post = posted[0][1]
    assert posted[0][0] == "/api/collections/support_customer_portal_sessions/records"
    assert portal_post["token_hash"] != "portal-token"
