def test_get_customer_portal_filters_private_messages(monkeypatch):
    patched: list[tuple[str, dict]] = []
    session = {
        "id": "portal123",
        "issue": "issue1",
        "tenant": "tenant1",
        "project": "project1",
        "status": "active",
        "expires_at": "2030-07-01T10:00:00+00:00",
    }
    issue = {
        "id": "issue1",
        "subject": "Need help",
        "status": "open",
        "priority": "normal",
        "messages": [
            {"id": "msg1", "direction": "customer", "sender": "customer@example.com", "body": "Question"},
            {"id": "msg2", "direction": "ai", "sender": "AI assistant", "body": "Draft"},
            {"id": "msg3", "direction": "agent", "sender": "agent@example.com", "body": "Answer"},
            {"id": "msg4", "direction": "internal", "sender": "agent@example.com", "body": "Private"},
        ],
    }

    def fake_first(collection: str, *_args, **_kwargs):
        if collection == "support_customer_portal_sessions":
            return session
        if collection == "support_csat_feedback":
            return {
                "id": "feedback1",
                "issue": "issue1",
                "portal_session": "portal123",
                "rating": 4,
                "comment": "Helpful",
                "customer_email": "customer@example.com",
                "source": "customer_portal",
            }
        return None

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "get_issue", lambda *_args, **_kwargs: issue)

    portal = issues.get_customer_portal("portal-token")

    assert portal is not None
    assert portal["session"]["tenantId"] == "tenant1"
    assert portal["session"]["projectId"] == "project1"
    assert [message["id"] for message in portal["issue"]["messages"]] == ["msg1", "msg3"]
    assert portal["feedback"]["rating"] == 4
    assert patched[0][0] == "/api/collections/support_customer_portal_sessions/records/portal123"
    assert "last_accessed_at" in patched[0][1]


