def test_get_web_chat_session_returns_latest_issue(monkeypatch):
    requested_issue_ids: list[str] = []
    session = {
        "id": "session1",
        "project": "project1",
        "tenant": "tenant1",
        "issue": "issue1",
        "session_key": "web-session-token",
        "metadata": {"issueIds": ["issue1", "issue2"], "latestIssueId": "issue2", "ticketCreationMode": "per_message"},
    }

    monkeypatch.setattr(
        issues,
        "_first",
        lambda collection, *_args, **_kwargs: session if collection == "support_web_chat_sessions" else None,
    )

    def fake_get_issue(issue_id: str, **_kwargs):
        requested_issue_ids.append(issue_id)
        return {"id": issue_id, "messages": [{"id": "msg2"}]}

    monkeypatch.setattr(issues, "get_issue", fake_get_issue)

    def fake_list_all(collection: str, filter_expr: str, *_args, **_kwargs):
        if collection != "support_messages":
            return []
        if "issue='issue1'" in filter_expr:
            return [
                {
                    "id": "msg1",
                    "issue": "issue1",
                    "source_message_id": "web-chat:session1:msg1",
                    "direction": "customer",
                    "sender": "Ana",
                    "body": "First message",
                    "message_kind": "web_chat_message",
                    "metadata": {"webChatSessionId": "session1"},
                    "occurred_at": "2026-07-03T09:00:00+00:00",
                },
                {
                    "id": "reply1",
                    "issue": "issue1",
                    "source_message_id": "outbound:reply1",
                    "direction": "agent",
                    "sender": "Agent",
                    "body": "First reply",
                    "message_kind": "outbound_reply",
                    "metadata": {"webChatSessionId": "session1"},
                    "occurred_at": "2026-07-03T09:01:00+00:00",
                },
            ]
        if "issue='issue2'" in filter_expr:
            return [
                {
                    "id": "msg2",
                    "issue": "issue2",
                    "source_message_id": "web-chat:session1:msg2",
                    "direction": "customer",
                    "sender": "Ana",
                    "body": "Second ticket",
                    "message_kind": "web_chat_message",
                    "metadata": {"webChatSessionId": "session1"},
                    "occurred_at": "2026-07-03T09:02:00+00:00",
                },
            ]
        return []

    monkeypatch.setattr(issues, "_list_all", fake_list_all)

    result = issues.get_web_chat_session("web-session-token")

    assert result is not None
    assert requested_issue_ids == ["issue2"]
    assert result["issue"]["id"] == "issue2"
    assert result["session"]["issueIds"] == ["issue1", "issue2"]
    assert result["session"]["latestIssueId"] == "issue2"
    assert result["session"]["messageCount"] == 3
    assert result["sessionKey"] == "web-session-token"
    assert result["issueId"] == "issue2"
    assert result["issueIds"] == ["issue1", "issue2"]
    assert result["latestIssueId"] == "issue2"
    assert result["messageCount"] == 3
    assert [message["body"] for message in result["messages"]] == ["First message", "First reply", "Second ticket"]
    assert [message["issueId"] for message in result["messages"]] == ["issue1", "issue1", "issue2"]


