def test_run_automation_rules_for_backlog_runs_open_issue_rules(monkeypatch):
    calls: list[dict] = []
    issues_seen = [
        {"id": "issue1", "status": "open", "priority": "high", "requiresHuman": True},
        {"id": "issue2", "status": "open", "priority": "normal", "requiresHuman": True},
    ]

    monkeypatch.setattr(
        issues,
        "list_issues",
        lambda **kwargs: calls.append({"kind": "list", **kwargs}) or issues_seen,
    )

    def fake_run(**kwargs):
        calls.append({"kind": "run", **kwargs})
        issue_id = kwargs["issue"]["id"]
        if issue_id == "issue1":
            return {"processed": 1, "failed": 0, "items": [{"id": "run1"}]}
        return {"processed": 0, "failed": 0, "items": []}

    monkeypatch.setattr(issues, "_run_automation_rules_for_issue", fake_run)

    result = issues.run_automation_rules_for_backlog(
        tenant_id="tenant1",
        project_id="project1",
        trigger="issue_created",
        status="open",
        queue_key="support",
        limit=25,
        actor_email="lead@example.com",
    )

    assert result["issues"] == 2
    assert result["processed"] == 1
    assert result["skipped"] == 1
    assert result["failed"] == 0
    assert result["runs"] == 1
    assert result["items"][0]["issueId"] == "issue1"
    assert result["items"][1]["skipped"] is True
    assert calls[0] == {
        "kind": "list",
        "tenant_id": "tenant1",
        "project_id": "project1",
        "status": "open",
        "queue_key": "support",
        "limit": 25,
    }
    assert calls[1]["kind"] == "run"
    assert calls[1]["trigger"] == "issue_created"
    assert calls[1]["context"]["backlog"] is True
    assert calls[1]["actor_email"] == "lead@example.com"


