def test_channel_launch_playbook_guides_slack_setup():
    playbook = admin_channel_api._channel_launch_playbook(
        {"id": "channel1", "type": "slack", "channelKey": "slack-main"},
        {
            "providerWebhookUrl": "https://api.example.test/api/internal/support/slack/slack-main",
            "inboundWebhookUrl": "https://api.example.test/api/internal/support/channel-webhooks/slack-main",
            "health": {
                "ready": False,
                "status": "degraded",
                "requiredMissingEnvVars": [],
            },
            "launch": {
                "blockers": [
                    {
                        "key": "owner_routing",
                        "label": "Default owner routing",
                        "action": "owner_routing",
                    },
                ],
            },
            "launchChecklist": [
                {"key": "inbound_smoke", "status": "missing"},
                {"key": "outbound_smoke", "status": "done"},
                {"key": "lifecycle_smoke", "status": "missing"},
                {"key": "attachment_lifecycle_smoke", "status": "missing"},
            ],
        },
        "project1",
    )

    by_key = {step["key"]: step for step in playbook}
    assert by_key["endpoint"]["action"] == "copy"
    assert by_key["endpoint"]["copyLabel"] == "Provider URL"
    assert by_key["provider_install"]["action"] == "install_slack"
    assert by_key["ticket_defaults"]["status"] == "missing"
    assert by_key["ticket_defaults"]["runAction"] == "owner_routing"
    assert by_key["validate_setup"]["status"] == "warning"
    assert by_key["validate_setup"]["runAction"] == "provider_validation"
    assert by_key["inbound_proof"]["runAction"] == "inbound_smoke"
    assert by_key["outbound_proof"]["status"] == "done"
    assert by_key["lifecycle_proof"]["runAction"] == "lifecycle_smoke"
    assert by_key["lifecycle_proof"]["smokeCommand"] == (
        "SUPPORT_PROJECT_ID=project1 ADMIN_AUTH_TOKEN=<admin-api-token> "
        "./support-channel-lifecycle-smoke.sh --channel-key slack-main --transport http"
    )
    assert by_key["attachment_lifecycle_proof"]["runAction"] == "attachment_lifecycle_smoke"
    assert "--attachment" in by_key["attachment_lifecycle_proof"]["smokeCommand"]
    assert "--body \"\"" in by_key["attachment_lifecycle_proof"]["smokeCommand"]


