    assert timeline_messages[0]["source_message_id"] == "outbound:reply123"
    assert timeline_messages[0]["metadata"]["deliveryReceipt"]["eventType"] == "delivered"
    assert timeline_messages[0]["metadata"]["providerMessageId"] == "smtp:reply123"
    assert sla_patch["status"] == "met"
