def test_ingest_channel_webhook_matches_native_channel_receipt_ids(monkeypatch, case):
    posted: list[tuple[str, dict]] = []
    patched: list[tuple[str, dict]] = []
    filters: list[str] = []
    monkeypatch.setattr(issues, "generate_id", lambda: "channelEvent123")

    def fake_first(collection: str, filter_str: str):
        filters.append(filter_str)
        if collection == "support_channels":
            return {
                "id": "channel1",
                "tenant": "tenant1",
                "project": "project1",
                "channel_key": case["channel_key"],
                "type": case["provider"],
                "name": case["provider"].title(),
                "status": "active",
                "config": {},
            }
        if collection == "support_channel_webhook_events":
            if "id='channelEvent123'" in filter_str:
                return {"id": "channelEvent123", "channel": "channel1", "status": "received"}
            return None
        if collection == "support_messages":
            return None
        if collection == "support_outbound_messages":
            expected = case["stored_provider_message_id"]
            if f"provider_message_id='{expected}'" in filter_str:
                return {
                    "id": "reply123",
                    "tenant": "tenant1",
                    "project": "project1",
                    "issue": "issue1",
                    "channel": case["provider"],
                    "to_address": "customer",
                    "body": "Done.",
                    "status": "queued",
                    "provider": case["provider"],
                    "provider_message_id": expected,
                    "created_by": "agent@example.com",
                    "metadata": {},
                }
        return None

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(
        issues,
        "_get",
        lambda *_args, **_kwargs: (_ for _ in ()).throw(AssertionError("exact provider id should match")),
    )
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)

    result = issues.ingest_channel_webhook(
        case["channel_key"],
        tenant_id="tenant1",
        project_id="project1",
        payload=case["payload"],
    )

    expected = case["stored_provider_message_id"]
    assert result["status"] == "success"
    assert result["processed"] == 1
    assert any(f"provider_message_id='{expected}'" in filter_str for filter_str in filters)
    webhook_post = next(data for path, data in posted if path == "/api/collections/support_channel_webhook_events/records")
    outbound_patch = next(data for path, data in patched if path == "/api/collections/support_outbound_messages/records/reply123")
    webhook_patch = next(data for path, data in patched if path == "/api/collections/support_channel_webhook_events/records/channelEvent123")
    assert webhook_post["provider_message_id"] == expected
    assert outbound_patch["provider_message_id"] == expected
    assert outbound_patch["metadata"]["deliveryReceipt"]["providerMessageId"] == expected
    assert webhook_patch["result"]["providerMessageId"] == expected
    assert webhook_patch["outbound_message"] == "reply123"


