def test_ingest_channel_webhook_creates_generic_message_ticket(monkeypatch):
    ids = iter(["eventRow1", "issue1", "msg1"])
    posted: list[tuple[str, dict]] = []
    patched: list[tuple[str, dict]] = []
    automations: list[dict] = []
    account_insight_calls: list[dict] = []

