def test_ingest_channel_webhook_marks_failed_receipt(monkeypatch):
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []

    def fake_first(collection: str, filter_str: str):
        if collection == "support_channels":
            return {"id": "channel1", "tenant": "tenant1", "project": "project1", "channel_key": "email:support", "type": "email"}
        if collection == "support_channel_webhook_events":
            if "id='eventRow1'" in filter_str:
                return {"id": "eventRow1", "channel": "channel1", "event_id": "bounce:mail-1", "status": "received"}
            return None
        if collection == "support_outbound_messages":
            return {
                "id": "reply123",
                "issue": "issue1",
                "status": "sent",
                "provider_message_id": "mail-1",
                "created_by": "agent@example.com",
                "subject": "Re: Need help",
                "metadata": {},
            }
        if collection == "support_issues":
            return {
                "id": "issue1",
                "subject": "Need help",
                "assignee_email": "owner@example.com",
            }
        return None

    monkeypatch.setattr(issues, "generate_id", lambda: "eventRow1")
    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_list_all", lambda collection, *_args, **_kwargs: [])
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or data)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)

    result = issues.ingest_channel_webhook(
        "email:support",
        tenant_id="tenant1",
        project_id="project1",
        payload={"eventType": "bounced", "providerMessageId": "mail-1", "reason": "Mailbox missing"},
    )

    outbound_patch = next(data for path, data in patched if path == "/api/collections/support_outbound_messages/records/reply123")
    issue_event = next(data for path, data in posted if path == "/api/collections/support_issue_events/records")
    assert result["status"] == "success"
    assert outbound_patch["status"] == "failed"
    assert outbound_patch["error"] == "Mailbox missing"
    assert issue_event["event_type"] == "reply_delivery_failed"
    notifications = [data for path, data in posted if path == "/api/collections/support_notifications/records"]
    assert [item["recipient_email"] for item in notifications] == ["owner@example.com", "agent@example.com"]
    assert {item["type"] for item in notifications} == {"delivery_failed"}
    assert notifications[0]["body"] == "Mailbox missing"


def test_rematch_channel_webhook_event_applies_receipt(monkeypatch):
    patched: list[tuple[str, dict]] = []
