def test_due_soon_sla_filters_ignore_done_tickets():
    target = (issues._now_utc() + timedelta(minutes=30)).isoformat()

    assert issues._issue_matches_operational_filter(
        {"id": "issue-open", "status": "ongoing", "nextSlaTargetAt": target},
        "due-soon-sla",
    )
    assert not issues._issue_matches_operational_filter(
        {"id": "issue-done", "status": "done", "nextSlaTargetAt": target},
        "due-soon-sla",
    )
    assert not issues._issue_matches_operational_filter(
        {"id": "issue-done", "status": "done", "hasOverdueSla": True},
        "overdue-sla",
    )


