def test_merge_issues_moves_children_and_marks_source(monkeypatch):
    source = {
        "id": "source1",
        "status": "open",
        "priority": "urgent",
        "subject": "Duplicate outage",
        "tags": ["bug"],
        "message_count": 2,
        "latest_message_at": "2026-01-02T10:00:00+00:00",
        "requires_human": True,
        "action_log": [{"label": "source action"}],
    }
    target = {
        "id": "target1",
        "status": "ongoing",
        "priority": "normal",
        "subject": "Main outage",
        "tags": ["vip"],
        "message_count": 1,
        "latest_message_at": "2026-01-01T10:00:00+00:00",
        "requires_human": False,
        "action_log": [{"label": "target action"}],
    }
    patched: list[tuple[str, dict]] = []
    posted: list[tuple[str, dict]] = []

    def fake_first(collection: str, filter_str: str, *_args, **_kwargs):
        if collection == "support_issues" and "id='source1'" in filter_str:
            return source
        if collection == "support_issues" and "id='target1'" in filter_str:
            return target
        if collection == "support_messages" and "issue='target1'" in filter_str and "source_message_id='dup'" in filter_str:
            return {"id": "existingDup"}
        if (
            collection == "support_outbound_messages"
            and "issue='target1'" in filter_str
            and "idempotency_key='reply-dup'" in filter_str
        ):
            return {"id": "existingReplyDup"}
        return None

    def fake_list_all(collection: str, filter_str: str = "", *_args, **_kwargs):
        if collection == "support_messages" and "issue='source1'" in filter_str:
            return [
                {"id": "msg1", "source_message_id": "src-1"},
                {"id": "msgDup", "source_message_id": "dup"},
            ]
        if collection == "support_messages" and "issue='target1'" in filter_str:
            return [
                {"id": "targetMsg", "occurred_at": "2026-01-01T10:00:00+00:00"},
                {"id": "msg1", "occurred_at": "2026-01-02T10:00:00+00:00"},
            ]
        if collection == "support_internal_notes" and "issue='source1'" in filter_str:
            return [{"id": "note1"}]
        if collection == "support_outbound_messages" and "issue='source1'" in filter_str:
            return [
                {"id": "reply1", "idempotency_key": "reply-unique"},
                {"id": "replyDup", "idempotency_key": "reply-dup"},
            ]
        return []

    monkeypatch.setattr(issues, "_first", fake_first)
    monkeypatch.setattr(issues, "_list_all", fake_list_all)
    monkeypatch.setattr(issues, "_patch", lambda path, data: patched.append((path, data)) or data)
    monkeypatch.setattr(issues, "_post", lambda path, data: posted.append((path, data)) or {"id": "event1", **data})

    result = issues.merge_issues(
        "source1",
        target_issue_id="target1",
        tenant_id="tenant1",
        project_id="project1",
        actor_email="agent@example.com",
        note="Same outage thread",
    )

    assert result and result["id"] == "target1"
    patch_by_path = dict(patched)
    assert patch_by_path["/api/collections/support_messages/records/msg1"] == {"issue": "target1"}
    assert "/api/collections/support_messages/records/msgDup" not in patch_by_path
    assert patch_by_path["/api/collections/support_internal_notes/records/note1"] == {"issue": "target1"}
    assert patch_by_path["/api/collections/support_outbound_messages/records/reply1"] == {"issue": "target1"}
    assert "/api/collections/support_outbound_messages/records/replyDup" not in patch_by_path
    target_patch = patch_by_path["/api/collections/support_issues/records/target1"]
    assert target_patch["priority"] == "urgent"
    assert target_patch["tags"] == ["vip", "bug"]
    assert target_patch["message_count"] == 2
    source_patch = patch_by_path["/api/collections/support_issues/records/source1"]
    assert source_patch["status"] == "done"
    assert source_patch["merged_into_issue"] == "target1"
    assert source_patch["merged_by"] == "agent@example.com"
    assert source_patch["merge_note"] == "Same outage thread"
    assert "merged" in source_patch["tags"]
    event_types = [data["event_type"] for path, data in posted if path == "/api/collections/support_issue_events/records"]
    assert event_types == ["issue_merged", "issue_merged_into"]


